/* ─────────────── Animation Variants ─────────────── */
const fadeUp = {
  hidden: { opacity: 0, y: 30 },
  visible: (i = 0) => ({
    opacity: 1, y: 0,
    transition: { delay: i * 0.1, duration: 0.6, ease: [0.22, 1, 0.36, 1] }
  })
};

const stagger = {
  visible: { transition: { staggerChildren: 0.08 } }
};

/* ─────────────── THEME HOOK ─────────────── */
function useTheme() {
  const [theme, setTheme] = useState('dark');

  useEffect(() => {
    const saved = localStorage.getItem('allbot-theme');
    const initial = saved || 'dark';
    setTheme(initial);
    document.documentElement.setAttribute('data-theme', initial);
  }, []);

  const toggleTheme = () => {
    const next = theme === 'dark' ? 'light' : 'dark';
    setTheme(next);
    document.documentElement.setAttribute('data-theme', next);
    localStorage.setItem('allbot-theme', next);
  };

  return { theme, toggleTheme };
}

/* ─────────────── THEME TOGGLE ─────────────── */
function ThemeToggle({ theme, toggleTheme }) {
  return (
    <button
      className="theme-toggle"
      onClick={toggleTheme}
      aria-label={`Switch to ${theme === 'dark' ? 'light' : 'dark'} mode`}
      title={`Switch to ${theme === 'dark' ? 'light' : 'dark'} mode`}
    >
      <Sun size={20} className={`theme-icon ${theme === 'light' ? 'visible' : 'hidden'}`} />
      <Moon size={20} className={`theme-icon ${theme === 'dark' ? 'visible' : 'hidden'}`} />
    </button>
  );
}

/* ─────────────── NAVBAR ─────────────── */
